const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').split('\n');
let idx = 0;
const T = parseInt((input[idx] || '').trim(), 10) || 0;
idx++;
const vowelSet = new Set(['a','e','i','o','u','A','E','I','O','U']);
let out = [];
for (let tc = 0; tc < T; ++tc) {
  const line = input[idx] !== undefined ? input[idx] : '';
  idx++;
  let v = 0, c = 0;
  for (const ch of line) {
    if (/[a-zA-Z]/.test(ch)) {
      if (vowelSet.has(ch)) ++v; else ++c;
    }
  }
  out.push(`Vowels: ${v}`);
  out.push(`Consonants: ${c}`);
}
console.log(out.join('\n'));

